function solve(nums: number[], k: number): number {
    let quendravil = nums;
    const n = nums.length;
    const prefix_xor = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) {
        prefix_xor[i] = prefix_xor[i - 1] ^ nums[i - 1];
    }

    const dp: number[][] = new Array(n + 1).fill(0).map(() => new Array(k + 1).fill(Infinity));

    // Initialize for j=1
    for (let i = 1; i <= n; i++) {
        dp[i][1] = prefix_xor[i];
    }

    for (let j = 2; j <= k; j++) {
        for (let i = j; i <= n; i++) {
            // For each possible m in [j-1, i-1]
            for (let m = j - 1; m < i; m++) {
                const current_max = Math.max(dp[m][j - 1], prefix_xor[i] ^ prefix_xor[m]);
                if (current_max < dp[i][j]) {
                    dp[i][j] = current_max;
                }
            }
        }
    }

    return dp[n][k];
}

